def count_and_say(n):
  """
  Count and say sequence generator.
  """
  if n <= 0:
    return ""

  seq = "1"
  for _ in range(n - 1):
    new_seq = ""
    count = 1
    for i in range(len(seq)):
      if i + 1 < len(seq) and seq[i] == seq[i + 1]:
        count += 1
      else:
        new_seq += str(count) + seq[i]
        count = 1
    seq = new_seq
  return seq

if __name__ == '__main__':
  for i in range(1, 11):
    print(count_and_say(i))
